async (page) => {
  // Focus canvas first, then try arrow key movement east
  await page.evaluate(() => {
    const canvas = document.getElementById('canvas');
    canvas.focus();
    canvas.dispatchEvent(new MouseEvent('click', { clientX: 400, clientY: 300, bubbles: true, ctrlKey: false }));
  });
  await page.waitForTimeout(500);

  // Press right arrow key multiple times to move east
  for (let i = 0; i < 30; i++) {
    await page.keyboard.press('ArrowRight');
    await page.waitForTimeout(200);
  }

  const state = await page.evaluate(() => JSON.stringify(window.__latestGameState));
  const parsed = JSON.parse(state);
  return JSON.stringify({ pos: parsed.player_position });
}

